{
  "name": "Barcode PDF Cropper",
  "description": "A precise PDF cropping tool designed to extract 3cm x 4cm barcode labels from larger PDF documents."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Dimensions {
  width: number;
  height: number;
}

export interface CropBox {
  x: number;
  y: number;
  width: number;
  height: number;
}

// 1 inch = 72 points
// 1 cm = 0.393701 inches
// 3cm = 1.1811 inches * 72 = 85.039 points
// 4cm = 1.5748 inches * 72 = 113.386 points

export const MM_TO_POINT = 72 / 25.4;

export const TARGET_WIDTH_MM = 30;
export const TARGET_HEIGHT_MM = 40;

export const TARGET_WIDTH_PT = TARGET_WIDTH_MM * MM_TO_POINT;
export const TARGET_HEIGHT_PT = TARGET_HEIGHT_MM * MM_TO_POINT;

