  const [file, setFile] = useState<File | null>(null);

  const handleFileSelect = (selectedFile: File) => {
    setFile(selectedFile);
  };

  const handleReset = () => {
    setFile(null);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-800">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-brand-600 text-white p-2 rounded-lg">
              <Scissors size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">
              条码裁切大师 <span className="text-xs font-normal text-slate-500 ml-1 px-2 py-0.5 bg-slate-100 rounded-full">3cm x 4cm</span>
            </h1>
          </div>
          {file && (
             <button
              onClick={handleReset}
              className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-brand-600 transition-colors"
            >
              <RefreshCw size={16} />
              重新上传
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 bg-slate-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 h-full">
          {!file ? (
            <div className="max-w-2xl mx-auto mt-12">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 text-center">
                <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-6">
                  <Upload size={32} />
                </div>
                <h2 className="text-2xl font-bold mb-2">上传 PDF 文件</h2>
                <p className="text-slate-500 mb-8">
                  请上传包含条形码的 PDF 文件。我们将帮助您提取左下角的条码并裁切为标准 3cm x 4cm 尺寸。
                </p>
                <FileUploader onFileSelect={handleFileSelect} />

                <div className="mt-8 grid grid-cols-1 sm:grid-cols-3 gap-4 text-left">
                  <FeatureItem 
                    icon={<FileCheck className="text-green-500" size={20}/>}
                    title="自动识别"
                    desc="默认定位左下角"
                  />
                  <FeatureItem 
                    icon={<Scissors className="text-brand-500" size={20}/>}
                    title="精准裁切"
                    desc="30mm x 40mm 标准"
                  />
                  <FeatureItem 
                    icon={<Upload className="text-purple-500" size={20}/>}
