);

export default App;

import React, { useRef, useState } from 'react';
import { UploadCloud, FileText } from 'lucide-react';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
}

const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const droppedFile = e.dataTransfer.files[0];
      if (droppedFile.type === 'application/pdf') {
        onFileSelect(droppedFile);
      } else {
        alert('请只上传 PDF 文件');
      }
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onFileSelect(e.target.files[0]);
    }
  };

  return (
    <div
      onClick={() => fileInputRef.current?.click()}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`
        relative group cursor-pointer
        border-2 border-dashed rounded-xl p-10
        flex flex-col items-center justify-center
        transition-all duration-200 ease-in-out
        ${isDragging 
          ? 'border-brand-500 bg-brand-50' 
          : 'border-slate-300 hover:border-brand-400 hover:bg-slate-50'
        }
      `}
    >
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileInput}
        accept="application/pdf"
        className="hidden"
      />

      <div className={`
        p-4 rounded-full mb-4 transition-colors duration-200
        ${isDragging ? 'bg-brand-100 text-brand-600' : 'bg-slate-100 text-slate-400 group-hover:bg-brand-50 group-hover:text-brand-500'}
      `}>
        {isDragging ? <UploadCloud size={32} /> : <FileText size={32} />}
      </div>

      <p className="text-lg font-medium text-slate-700 mb-1">
        点击或拖拽 PDF 文件至此处
      </p>
      <p className="text-sm text-slate-400">
        支持 PDF 格式
      </p>
    </div>
  );
};

export default FileUploader;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import { PDFDocument } from 'pdf-lib';
import { Download, ZoomIn, ZoomOut, Move, AlertCircle, Loader2 } from 'lucide-react';
import { TARGET_WIDTH_PT, TARGET_HEIGHT_PT, TARGET_WIDTH_MM, TARGET_HEIGHT_MM } from '../types';

// Initialize PDF worker
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

interface PdfCropperProps {
  file: File;
}

const PdfCropper: React.FC<PdfCropperProps> = ({ file }) => {
  const [numPages, setNumPages] = useState<number>(0);
  const [pageNumber, setPageNumber] = useState<number>(1);
  const [scale, setScale] = useState<number>(1.0);
  const [pdfDimensions, setPdfDimensions] = useState<{ width: number; height: number } | null>(null);
  const [containerWidth, setContainerWidth] = useState<number>(0);
  const [isProcessing, setIsProcessing] = useState(false);

  // Crop box position in percentages (0-100) to be responsive
  const [cropPos, setCropPos] = useState({ x: 0, y: 100 }); // Start bottom-left roughly

  const containerRef = useRef<HTMLDivElement>(null);
  const dragRef = useRef<{ isDragging: boolean; startX: number; startY: number; initialLeft: number; initialTop: number }>({
    isDragging: false,
    startX: 0,
    startY: 0,
    initialLeft: 0,
    initialTop: 0
  });

  // Calculate the physical size of the crop box in pixels based on current scale
  // TARGET_WIDTH_PT is in points. 1 point = 1/72 inch.
  // react-pdf renders at 72dpi by default when scale is 1? Actually slightly complex.
  // We need to know the ratio of (Rendered Pixels / PDF Points).

  const [renderedScaleRatio, setRenderedScaleRatio] = useState(1);

  // Load document success
  function onDocumentLoadSuccess({ numPages }: { numPages: number }) {
    setNumPages(numPages);
  }

  // Load page success to get dimensions
  function onPageLoadSuccess(page: any) {
    // originalWidth/Height are in PDF points
    setPdfDimensions({ width: page.originalWidth, height: page.originalHeight });

    // We want the box to start at bottom left
    // We will set this after we calculate the pixel dimensions
  }

  // Handle container resize to fit PDF
  useEffect(() => {
    if (containerRef.current) {
      setContainerWidth(containerRef.current.clientWidth);

      const resizeObserver = new ResizeObserver((entries) => {
        for (let entry of entries) {
          setContainerWidth(entry.contentRect.width);
        }
      });

      resizeObserver.observe(containerRef.current);
      return () => resizeObserver.disconnect();
    }
  }, []);

  // Calculate box pixel size
  const boxPixelSize = useMemo(() => {
    if (!pdfDimensions) return { width: 0, height: 0 };

    // If we rely on react-pdf "width" prop, it scales the PDF to that width in px.
    // The ratio of Pixels/Points = RenderedWidthPx / OriginalWidthPt.

    // Rendered width:
    const renderedWidth = containerWidth < 800 ? containerWidth - 32 : 800; // Constrain max width
    const actualRenderedWidth = renderedWidth * scale;

    const ratio = actualRenderedWidth / pdfDimensions.width;

    // Update ref for crop logic later (use effect to avoid render loop if we set state)
    // We'll calculate ratio on the fly during render to ensure sync.

    return {
      width: TARGET_WIDTH_PT * ratio,
      height: TARGET_HEIGHT_PT * ratio,
      ratio: ratio,
      renderedWidth: actualRenderedWidth,
      renderedHeight: pdfDimensions.height * ratio
    };
  }, [pdfDimensions, containerWidth, scale]);

  // Initial positioning logic
  useEffect(() => {
    // Only set initial position once dimensions are loaded
    if (boxPixelSize.width > 0 && cropPos.y === 100) {
      // Default to Bottom-Left
      // x = 0 + margin
      // y = totalHeight - boxHeight - margin
      // Let's use 5% margins
      const initialX = 0; // Left aligned
      const initialY = boxPixelSize.renderedHeight - boxPixelSize.height; // Bottom aligned

      setCropPos({ x: initialX, y: initialY });
    }
  }, [boxPixelSize.renderedHeight]);


  // Drag Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    dragRef.current = {
      isDragging: true,
      startX: e.clientX,
      startY: e.clientY,
      initialLeft: cropPos.x,
      initialTop: cropPos.y
    };
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!dragRef.current.isDragging) return;

    const deltaX = e.clientX - dragRef.current.startX;
    const deltaY = e.clientY - dragRef.current.startY;

    let newX = dragRef.current.initialLeft + deltaX;
    let newY = dragRef.current.initialTop + deltaY;

    // Boundaries
    newX = Math.max(0, Math.min(newX, boxPixelSize.renderedWidth - boxPixelSize.width));
    newY = Math.max(0, Math.min(newY, boxPixelSize.renderedHeight - boxPixelSize.height));

    setCropPos({ x: newX, y: newY });
  };

  const handleMouseUp = () => {
    dragRef.current.isDragging = false;
    document.removeEventListener('mousemove', handleMouseMove);
    document.removeEventListener('mouseup', handleMouseUp);
  };


  // Core Crop Logic
  const handleCropAndDownload = async () => {
    if (!file || !pdfDimensions) return;
    setIsProcessing(true);

    try {
      const arrayBuffer = await file.arrayBuffer();
      const pdfDoc = await PDFDocument.load(arrayBuffer);
      const pages = pdfDoc.getPages();
      const page = pages[pageNumber - 1]; // 0-based index

      // Calculate Crop Coordinates in PDF Points
      // PDF Coordinate System: (0,0) is usually Bottom-Left.
      // HTML System: (0,0) is Top-Left.

      // 1. Convert screen pixel position to PDF points
      const ratio = boxPixelSize.ratio;

      // x_pt = x_px / ratio
      const x_pt = cropPos.x / ratio;

      // y_px is distance from TOP.
      // y_pt needs distance from BOTTOM.
      // y_pt = (RenderedHeight_px - y_px - BoxHeight_px) / ratio
      // OR: y_pt = (TotalHeight_pt) - (y_px / ratio) - (BoxHeight_pt)
      const y_pt = pdfDimensions.height - (cropPos.y / ratio) - TARGET_HEIGHT_PT;

      console.log('Cropping at (pt):', { x: x_pt, y: y_pt, w: TARGET_WIDTH_PT, h: TARGET_HEIGHT_PT });

      // Create a NEW document for the clean 3x4cm output
      const newPdfDoc = await PDFDocument.create();

      // We want to embed the page from the source, but cropped.
      // pdf-lib doesn't support "embedding a cropped part" easily as an image.
      // Instead, we copy the page, set the crop box, and save.

      const [embeddedPage] = await newPdfDoc.copyPages(pdfDoc, [pageNumber - 1]);

      // Set the MediaBox (Physical page size) and CropBox (Visible area)
      // We want the final PDF to BE 3cm x 4cm.
      // So we set the MediaBox to the cropped area dimensions relative to the original page?
      // No, if we set MediaBox to [x, y, x+w, y+h], the viewer sees just that.
      // BUT, the coordinates of the content remain relative to the original origin.

      // Option A: Just modify the copied page's boxes.
      embeddedPage.setMediaBox(x_pt, y_pt, TARGET_WIDTH_PT, TARGET_HEIGHT_PT);
      embeddedPage.setCropBox(x_pt, y_pt, TARGET_WIDTH_PT, TARGET_HEIGHT_PT);

      newPdfDoc.addPage(embeddedPage);

      const pdfBytes = await newPdfDoc.save();

      // Download
      const blob = new Blob([pdfBytes], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cropped-label-${Date.now()}.pdf`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

    } catch (error) {
      console.error('Error cropping PDF:', error);
      alert('裁切失败，请检查文件是否损坏');
    } finally {
      setIsProcessing(false);
    }
  };

  const changeScale = (delta: number) => {
    setScale(prev => Math.max(0.5, Math.min(2.5, prev + delta)));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-full">
      {/* Sidebar Controls */}
      <div className="lg:w-80 flex flex-col gap-6 order-2 lg:order-1">
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
          <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Move size={18} className="text-brand-600" />
            裁切控制
          </h3>

          <div className="space-y-4">
            <div className="p-3 bg-slate-50 rounded-lg text-sm text-slate-600">
              <p>目标尺寸: <span className="font-mono font-bold text-slate-900">{TARGET_WIDTH_MM}mm x {TARGET_HEIGHT_MM}mm</span></p>
              <p className="mt-1 text-xs text-slate-500">拖动右侧预览图中的蓝色方框来选择裁切区域。</p>
            </div>

            <div className="flex items-center justify-between border-t border-slate-100 pt-4">
              <span className="text-sm text-slate-600">缩放视图</span>
              <div className="flex items-center gap-2">
                <button onClick={() => changeScale(-0.1)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600 transition-colors">
                  <ZoomOut size={18} />
                </button>
                <span className="text-sm font-mono w-12 text-center">{Math.round(scale * 100)}%</span>
                <button onClick={() => changeScale(0.1)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600 transition-colors">
                  <ZoomIn size={18} />
                </button>
              </div>
            </div>

            {numPages > 1 && (
              <div className="flex items-center justify-between border-t border-slate-100 pt-4">
                <span className="text-sm text-slate-600">选择页面</span>
                <div className="flex items-center gap-2">
                   <button 
                    disabled={pageNumber <= 1}
                    onClick={() => setPageNumber(p => p - 1)}
                    className="px-2 py-1 text-xs border rounded hover:bg-slate-50 disabled:opacity-50"
                   >上一页</button>
                   <span className="text-sm">{pageNumber} / {numPages}</span>
                   <button 
                    disabled={pageNumber >= numPages}
                    onClick={() => setPageNumber(p => p + 1)}
                    className="px-2 py-1 text-xs border rounded hover:bg-slate-50 disabled:opacity-50"
                   >下一页</button>
                </div>
              </div>
            )}
          </div>

          <button
            onClick={handleCropAndDownload}
            disabled={isProcessing}
            className="w-full mt-6 bg-brand-600 hover:bg-brand-700 text-white py-3 rounded-lg font-medium shadow-sm shadow-brand-200 transition-all active:scale-[0.98] flex items-center justify-center gap-2"
          >
            {isProcessing ? (
              <>
                <Loader2 className="animate-spin" size={20} />
                处理中...
              </>
            ) : (
              <>
                <Download size={20} />
                裁切并下载
              </>
            )}
          </button>

          <div className="mt-4 flex items-start gap-2 text-xs text-amber-600 bg-amber-50 p-3 rounded-lg">
            <AlertCircle size={14} className="mt-0.5 shrink-0"/>
            <p>生成的 PDF 将仅包含选定的 3cm x 4cm 区域，适合标签打印机。</p>
          </div>
        </div>
      </div>

      {/* Main Preview Area */}
      <div className="flex-1 bg-slate-200/50 rounded-xl border border-slate-200 overflow-auto p-4 lg:p-8 flex justify-center items-start order-1 lg:order-2 relative" style={{ minHeight: '500px' }}>
        <div ref={containerRef} className="relative shadow-lg bg-white inline-block">
          <Document
            file={file}
            onLoadSuccess={onDocumentLoadSuccess}
            loading={
              <div className="flex flex-col items-center justify-center p-20 text-slate-400">
                <Loader2 className="animate-spin mb-2" size={32} />
                <p>加载 PDF...</p>
              </div>
            }
            error={
              <div className="flex flex-col items-center justify-center p-20 text-red-400">
                <AlertCircle size={32} className="mb-2" />
                <p>无法加载 PDF 文件</p>
              </div>
            }
          >
            <Page
              pageNumber={pageNumber}
              scale={scale}
              onLoadSuccess={onPageLoadSuccess}
              width={containerWidth < 800 ? containerWidth - 32 : 800}
              renderTextLayer={false}
              renderAnnotationLayer={false}
            />
          </Document>

          {/* Draggable Crop Overlay */}
          {boxPixelSize.width > 0 && (
            <div
              onMouseDown={handleMouseDown}
              style={{
                position: 'absolute',
                left: cropPos.x,
                top: cropPos.y,
                width: boxPixelSize.width,
                height: boxPixelSize.height,
                cursor: 'move',
              }}
              className="group z-10 box-content"
            >
              {/* Visible Border */}
              <div className="w-full h-full border-2 border-brand-500 bg-brand-500/20 shadow-[0_0_0_9999px_rgba(0,0,0,0.4)] transition-colors">
                {/* Dimensions Label */}
                <div className="absolute -top-6 left-0 bg-brand-600 text-white text-[10px] px-1.5 py-0.5 rounded shadow-sm whitespace-nowrap">
                  3cm x 4cm
                </div>

                {/* Center Crosshair for precision */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity">
                    <div className="absolute top-1/2 left-0 w-full h-[1px] bg-brand-500/50"></div>
                    <div className="absolute left-1/2 top-0 h-full w-[1px] bg-brand-500/50"></div>
                </div>

                {/* Corner Handles (Visual only, since size is fixed) */}
                <div className="absolute -top-1 -left-1 w-2 h-2 bg-brand-600"></div>
                <div className="absolute -top-1 -right-1 w-2 h-2 bg-brand-600"></div>
                <div className="absolute -bottom-1 -left-1 w-2 h-2 bg-brand-600"></div>
                <div className="absolute -bottom-1 -right-1 w-2 h-2 bg-brand-600"></div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PdfCropper;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import { PDFDocument } from 'pdf-lib';
import { Download, ZoomIn, ZoomOut, Move, AlertCircle, Loader2 } from 'lucide-react';
import { TARGET_WIDTH_PT, TARGET_HEIGHT_PT, TARGET_WIDTH_MM, TARGET_HEIGHT_MM } from '../types';

// Initialize PDF worker
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

interface PdfCropperProps {
  file: File;
}

const PdfCropper: React.FC<PdfCropperProps> = ({ file }) => {
  const [numPages, setNumPages] = useState<number>(0);
  const [pageNumber, setPageNumber] = useState<number>(1);
  const [scale, setScale] = useState<number>(1.0);
  const [pdfDimensions, setPdfDimensions] = useState<{ width: number; height: number } | null>(null);
  const [availableWidth, setAvailableWidth] = useState<number>(0);
  const [isProcessing, setIsProcessing] = useState(false);

  // Crop box position in percentages (0-100) to be responsive
  const [cropPos, setCropPos] = useState({ x: 0, y: 100 }); // Start bottom-left roughly

  // Wrapper ref calculates the available space
  const wrapperRef = useRef<HTMLDivElement>(null);

  const dragRef = useRef<{ isDragging: boolean; startX: number; startY: number; initialLeft: number; initialTop: number }>({
    isDragging: false,
    startX: 0,
    startY: 0,
    initialLeft: 0,
    initialTop: 0
  });

  // Load document success
  function onDocumentLoadSuccess({ numPages }: { numPages: number }) {
    setNumPages(numPages);
  }

  // Load page success to get dimensions
  function onPageLoadSuccess(page: any) {
    // originalWidth/Height are in PDF points
    setPdfDimensions({ width: page.originalWidth, height: page.originalHeight });
  }

  // Handle container resize to fit PDF
  useEffect(() => {
    if (wrapperRef.current) {
      setAvailableWidth(wrapperRef.current.clientWidth);

      const resizeObserver = new ResizeObserver((entries) => {
        for (let entry of entries) {
          setAvailableWidth(entry.contentRect.width);
        }
      });

      resizeObserver.observe(wrapperRef.current);
      return () => resizeObserver.disconnect();
    }
  }, []);

  // Calculate rendered width based on available space and zoom
  const pdfPageWidth = useMemo(() => {
    // Subtract padding (approx 48px to 64px total horizontal padding)
    const padding = 64; 
    const maxBaseWidth = 800;

    // The base width is the size that fits in the container (responsive)
    const baseWidth = availableWidth > 0 
      ? Math.min(availableWidth - padding, maxBaseWidth) 
      : maxBaseWidth;

    // Apply zoom scale
    return baseWidth * scale;
  }, [availableWidth, scale]);

  // Calculate box pixel size
  const boxPixelSize = useMemo(() => {
    if (!pdfDimensions || pdfPageWidth === 0) return { width: 0, height: 0, ratio: 1, renderedWidth: 0, renderedHeight: 0 };

    // The ratio of Pixels/Points = RenderedWidthPx / OriginalWidthPt.
    const ratio = pdfPageWidth / pdfDimensions.width;

    return {
      width: TARGET_WIDTH_PT * ratio,
      height: TARGET_HEIGHT_PT * ratio,
      ratio: ratio,
      renderedWidth: pdfPageWidth,
      renderedHeight: pdfDimensions.height * ratio
    };
  }, [pdfDimensions, pdfPageWidth]);

  // Initial positioning logic
  useEffect(() => {
    // Only set initial position once dimensions are loaded and we haven't set it yet (y=100 is dummy)
    // We check if cropPos is at default state. 
    // Ideally we want to reset if file changes, but component remounts on file change in parent?
    // App.tsx conditionally renders PdfCropper when file exists. If file changes, does it remount?
    // React might reuse component if key is same. 
    // Let's assume on mount/dimensions ready we set it.

    if (boxPixelSize.renderedHeight > 0 && cropPos.y === 100) {
