// 1 inch = 72 points
// 1 cm = 0.393701 inches
// 3cm = 1.1811 inches * 72 = 85.039 points
// 4cm = 1.5748 inches * 72 = 113.386 points

export const MM_TO_POINT = 72 / 25.4;

