export const TARGET_WIDTH_MM = 40;
export const TARGET_HEIGHT_MM = 30;

export const TARGET_WIDTH_PT = TARGET_WIDTH_MM * MM_TO_POINT;
export const TARGET_HEIGHT_PT = TARGET_HEIGHT_MM * MM_TO_POINT;

