      embeddedPage.setMediaBox(x_pt, y_pt, TARGET_WIDTH_PT, TARGET_HEIGHT_PT);
      embeddedPage.setCropBox(x_pt, y_pt, TARGET_WIDTH_PT, TARGET_HEIGHT_PT);

